<body>
    <div class="status-container" id="statusContainer"></div>

    <script>
    const State = {
        loop: '1',
        worldId: 'W-001',
        scene: '未知',
        identity: '未知',
        goal: '未知',
        difficulty: '待生成',
        phase: '开局生成',
        location: '未知',
        time: '未知',
        survival: '存活',
        ruleTotal: 0,
        ruleVerified: 0,
        rules: []
    };

    function getAutoCardAPI() {
        if (typeof parent !== 'undefined' && parent.AutoCardUpdaterAPI) {
            return parent.AutoCardUpdaterAPI;
        }
        if (window.AutoCardUpdaterAPI) {
            return window.AutoCardUpdaterAPI;
        }
        return null;
    }

    async function loadTableData() {
        const api = getAutoCardAPI();
        if (!api) {
            console.log('[状态栏] API不可用，使用默认数据');
            renderUI();
            return;
        }

        try {
            const jsonData = await api.exportTableAsJson();
            const tables = typeof jsonData === 'string' ? JSON.parse(jsonData) : jsonData;
            parseTables(tables);
            renderUI();
        } catch (e) {
            console.error('[状态栏] 加载数据失败:', e);
            renderUI();
        }
    }

    function parseTables(tables) {
        State.rules = [];

        for (const uid in tables) {
            const sheet = tables[uid];
            if (!sheet || !sheet.content || sheet.content.length < 2) continue;

            const headers = sheet.content[0];
            const rows = sheet.content.slice(1);
            const get = (row, colName) => {
                const idx = headers.indexOf(colName);
                return idx !== -1 && idx < row.length ? row[idx] : undefined;
            };

            if (sheet.name === '全局轮回状态表' && rows.length > 0) {
                const row = rows[0];
                State.loop = get(row, '当前轮次') || '1';
                State.worldId = get(row, '当前世界编号') || 'W-001';
                State.scene = get(row, '当前场景') || '未知';
                State.identity = get(row, '当前身份') || '未知';
                State.goal = get(row, '当前目标') || '未知';
                State.difficulty = get(row, '当前难度') || '待生成';
                State.phase = get(row, '当前阶段') || '开局生成';
                State.location = get(row, '当前地点') || '未知';
                State.time = get(row, '当前时间') || '未知';
                State.survival = get(row, '存活状态') || '存活';
                State.ruleTotal = parseInt(get(row, '规则总数') || '0', 10) || 0;
                State.ruleVerified = parseInt(get(row, '已验证规则数') || '0', 10) || 0;
            }

            if (sheet.name === '规则追踪表') {
                State.rules = rows.map(row => ({
                    id: get(row, '规则编号') || '未知',
                    summary: get(row, '规则摘要') || '未知',
                    type: get(row, '规则类型') || '未知',
                    trust: get(row, '可信度') || '待验证',
                    status: get(row, '生效状态') || '未触发',
                    trigger: get(row, '触发条件') || '未知',
                    consequence: get(row, '违背后果') || '未知'
                })).filter(rule => rule.id && rule.id !== '');
            }
        }
    }

    function countBy(predicate) {
        return State.rules.filter(predicate).length;
    }

    function getSurvivalClass(value) {
        if (value === '消失') return 'dead';
        if (value === '濒危') return 'danger';
        return 'alive';
    }

    function getTrustClass(value) {
        if (value === '已确认') return 'confirmed';
        if (value === '已证伪') return 'false';
        return 'pending';
    }

    function escapeHtml(text) {
        const map = {
            '&': String.fromCharCode(38, 97, 109, 112, 59),
            '<': String.fromCharCode(38, 108, 116, 59),
            '>': String.fromCharCode(38, 103, 116, 59),
            '"': String.fromCharCode(38, 113, 117, 111, 116, 59),
            "'": String.fromCharCode(38, 35, 51, 57, 59)
        };
        return String(text ?? '').replace(/[&<>"']/g, ch => map[ch]);
    }

    function renderTopRules() {
        if (!State.rules.length) {
            return '<div class="empty-tip">当前世界尚未建立规则条目。</div>';
        }

        return State.rules.slice(-4).reverse().map(rule => {
            return `
                <div class="rule-item">
                    <div class="rule-head">
                        <div class="rule-id">${escapeHtml(rule.id)}</div>
                        <div class="mini-tag ${getTrustClass(rule.trust)}">${escapeHtml(rule.trust)}</div>
                    </div>
                    <div class="rule-title">${escapeHtml(rule.summary)}</div>
                    <div class="rule-meta">
                        <div class="mini-tag">${escapeHtml(rule.type)}</div>
                        <div class="mini-tag">${escapeHtml(rule.status)}</div>
                        <div class="mini-tag">触发：${escapeHtml(rule.trigger)}</div>
                    </div>
                </div>
            `;
        }).join('');
    }

    function renderUI() {
        const confirmedCount = countBy(rule => rule.trust === '已确认');
        const pendingCount = countBy(rule => rule.trust === '待验证' || rule.trust === '未知' || rule.trust === '较高');
        const falseCount = countBy(rule => rule.trust === '已证伪');
        const lethalCount = countBy(rule => rule.type === '致命禁则');
        const denominator = Math.max(State.ruleTotal, State.rules.length, 1);
        const progress = Math.max(0, Math.min(100, Math.round((State.ruleVerified / denominator) * 100)));

        const html = `
            <div class="topbar">
                <div class="topbar-left">
                    <div class="topbar-title">轮回禁则</div>
                    <div class="topbar-meta">第 ${escapeHtml(State.loop)} 轮 · 世界 ${escapeHtml(State.worldId)}</div>
                </div>
                <div class="status-pill ${getSurvivalClass(State.survival)}">${escapeHtml(State.survival)}</div>
            </div>

            <div class="grid">
                <section class="card">
                    <div class="card-title">◆ 世界配置</div>
                    <div class="info-list">
                        <div class="info-row"><div class="info-label">当前场景</div><div class="info-value">${escapeHtml(State.scene)}</div></div>
                        <div class="info-row"><div class="info-label">当前身份</div><div class="info-value">${escapeHtml(State.identity)}</div></div>
                        <div class="info-row"><div class="info-label">当前目标</div><div class="info-value">${escapeHtml(State.goal)}</div></div>
                        <div class="info-row"><div class="info-label">当前难度</div><div class="info-value">${escapeHtml(State.difficulty)}</div></div>
                        <div class="info-row"><div class="info-label">当前阶段</div><div class="info-value">${escapeHtml(State.phase)}</div></div>
                    </div>
                </section>

                <section class="card">
                    <div class="card-title">◆ 当前位置</div>
                    <div class="info-list">
